   AND EXEC_WT_NUM = #{EXEC_WT_NUM}

SELECT (CASE WHEN COUNT(*) > 0 THEN 'Y' ELSE 'N' END) AS PROGRESS_FLAG
  FROM STOCCNDT CNDT
  JOIN STOCCNHD CNHD
  	   ON( CNDT.GATE_CD  = CNHD.GATE_CD
  	   AND CNDT.BUYER_CD = CNHD.BUYER_CD
  	   AND CNDT.EXEC_NUM = CNHD.EXEC_NUM
  	   AND CNHD.DEL_FLAG = '0')
 WHERE CNDT.GATE_CD  = #{ses.gateCd}
   AND CNDT.BUYER_CD = #{BUYER_CD}
   AND CNDT.RFX_NUM  = #{REQ_NUM}
   AND CNDT.RFX_CNT  = #{REQ_CNT}

