SELECT HD.EXEC_NUM , HD.REF_DOC_NUM , HD.EXEC_SUBJECT ,(HD.EXEC_DATE, 'YYYYMMDD') AS EXEC_DATE , HD.CTRL_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.CTRL_USER_ID, #{ses.langCd}) AS CTRL_USER_NM , HD.CUR , HD.EXEC_AMT , HD.VAT_TYPE , HD.EXEC_DOIB_FLAG , HD.EXEC_TCO_FLAG , HD.RMK_TEXT_NUM , HD.ATT_FILE_NUM , HD.GATE_CD , HD.BUYER_CD , HD.DEPT_CD , HD.EXEC_TYPE , HD.APP_DOC_NUM , HD.APP_DOC_CNT , HD.SIGN_STATUS ,(CASE WHEN (SELECT COUNT(D.EXEC_SQ) FROM STOCCNDT D WHERE D.GATE_CD = HD.GATE_CD AND D.BUYER_CD = HD.BUYER_CD AND D.EXEC_NUM = HD.EXEC_NUM AND D.TCO_YEAR IS NOT NULL AND D.DEL_FLAG = '0') > 0 THEN 'Y' ELSE 'N' END) AS TCO_FLAG FROM STOCCNHD HD WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{BUYER_CD} AND HD.DEL_FLAG = '0'
AND HD.EXEC_NUM = #{EXEC_NUM}
AND HD.APP_DOC_NUM = #{APP_DOC_NUM} AND HD.APP_DOC_CNT = #{APP_DOC_CNT}

mapper.insert:
MERGE  STOCCNHD CNHD
USING (SELECT
             #{ses.gateCd} AS GATE_CD
            ,#{BUYER_CD} AS BUYER_CD
            ,#{EXEC_NUM} AS EXEC_NUM
         ) B
  ON (CNHD.GATE_CD  = B.GATE_CD
  AND CNHD.BUYER_CD = B.BUYER_CD
  AND CNHD.EXEC_NUM = B.EXEC_NUM)
WHEN MATCHED THEN
UPDATE SET
     MOD_DATE = SYSDATE
    ,MOD_USER_ID = #{ses.userId}
    ,REF_DOC_NUM = #{REF_DOC_NUM}
    ,EXEC_SUBJECT = #{EXEC_SUBJECT}
    ,EXEC_DOIB_FLAG = #{EXEC_DOIB_FLAG}
    ,EXEC_TCO_FLAG = #{EXEC_TCO_FLAG}
    ,EXEC_AMT = #{EXEC_AMT}
    ,RMK_TEXT_NUM = #{RMK_TEXT_NUM}
    ,ATT_FILE_NUM = #{ATT_FILE_NUM}
    ,SIGN_STATUS  = #{SIGN_STATUS}
WHEN NOT MATCHED THEN
INSERT (
     GATE_CD
    ,BUYER_CD
    ,EXEC_NUM
    ,REG_DATE
    ,REG_USER_ID
    ,MOD_DATE
    ,MOD_USER_ID
    ,DEL_FLAG
    ,DEPT_CD
    ,REF_DOC_NUM
    ,EXEC_TYPE
    ,EXEC_SUBJECT
    ,EXEC_DATE
    ,CTRL_USER_ID
    ,EXEC_DOIB_FLAG
    ,EXEC_TCO_FLAG
    ,CUR
    ,EXEC_AMT
    ,VAT_TYPE
    ,RMK_TEXT_NUM
    ,ATT_FILE_NUM
    ,SIGN_STATUS
) VALUES (
     #{ses.gateCd}
    ,#{BUYER_CD}
    ,#{EXEC_NUM}
    ,SYSDATE
    ,#{ses.userId}
    ,SYSDATE
    ,#{ses.userId}
    ,'0'
    ,#{DEPT_CD}
    ,#{REF_DOC_NUM}
    ,'G'
    ,#{EXEC_SUBJECT}
    ,(#{EXEC_DATE}, 'yyyyMMdd')
    ,#{CTRL_USER_ID}
    ,#{EXEC_DOIB_FLAG}
    ,#{EXEC_TCO_FLAG}
    ,#{CUR}
    ,#{EXEC_AMT}
    ,#{VAT_TYPE}
    ,#{RMK_TEXT_NUM}
    ,#{ATT_FILE_NUM}
    ,#{SIGN_STATUS}
)

MERGE  STOCCNVD CNVD
USING (SELECT
             #{ses.gateCd} AS GATE_CD
            ,#{BUYER_CD} AS BUYER_CD
            ,#{EXEC_NUM} AS EXEC_NUM
            ,#{VENDOR_CD} AS VENDOR_CD
         ) B
  ON (CNVD.GATE_CD = B.GATE_CD
  AND CNVD.BUYER_CD = B.BUYER_CD
  AND CNVD.EXEC_NUM = B.EXEC_NUM
  AND CNVD.VENDOR_CD = B.VENDOR_CD)
WHEN MATCHED THEN
UPDATE SET
     MOD_DATE = SYSDATE
    ,MOD_USER_ID = #{ses.userId}
    ,CONT_FLAG = #{CONT_FLAG}
    ,CONT_USER_ID = #{CONT_USER_ID}
    ,PO_USER_ID = #{PO_USER_ID}
WHEN NOT MATCHED THEN
INSERT (
     GATE_CD
    ,BUYER_CD
    ,EXEC_NUM
    ,VENDOR_CD
    ,REG_DATE
    ,REG_USER_ID
    ,MOD_DATE
    ,MOD_USER_ID
    ,DEL_FLAG
    ,CONT_FLAG
    ,PIC_USER_NM
    ,PIC_TEL_NUM
    ,PIC_EMAIL
    ,CONT_USER_ID
    ,PO_USER_ID
    ,RFX_AMT
)
VALUES (
     #{ses.gateCd}
    ,#{BUYER_CD}
    ,#{EXEC_NUM}
    ,#{VENDOR_CD}
    ,SYSDATE
    ,#{ses.userId}
    ,SYSDATE
    ,#{ses.userId}
    ,'0'
    ,#{CONT_FLAG}
    ,#{PIC_USER_NM}
    ,#{PIC_TEL_NUM}
    ,#{PIC_EMAIL}
    ,#{CONT_USER_ID}
    ,#{PO_USER_ID}
    ,#{RFX_AMT}
)

