    , #{EXEC_AMT}
    , #{SW_BUS_AMT}
    , #{MNT_SANGJU_YN}
    , #{CONSUMER_AMT}
    , #{FC_MNT_TERM}
    , #{CH_RATE}
    , #{DOIB_AMOUNT}
    , #{MNT_RATE}
    ,(#{MNT_SDAY}, 'yyyyMMdd')
