mapper.select:
SELECT A.PR_BUYER_CD ,getBuyerNames(A.GATE_CD, A.BUYER_CD, 'EX', A.EXEC_NUM, NULL, NULL, #{ses.langCd}) AS PR_BUYER_NM , A.SIGN_STATUS, A.EXEC_TYPE, A.EXEC_NUM, A.EXEC_SUBJECT , A.VENDOR_CDS, A.VENDOR_NMS , A.CUR, A.EXEC_AMT, A.VAT_TYPE , A.EXEC_DATE , A.CTRL_USER_ID, GETUSERNAME(A.GATE_CD, A.CTRL_USER_ID, #{ses.langCd}) AS CTRL_USER_NM , A.BUYER_CD FROM ( SELECT HD.GATE_CD, HD.BUYER_CD, HD.EXEC_NUM ,(SELECT MAX(CNDT.PR_BUYER_CD) FROM STOCCNDT CNDT WHERE CNDT.GATE_CD = HD.GATE_CD AND CNDT.BUYER_CD = HD.BUYER_CD AND CNDT.EXEC_NUM = HD.EXEC_NUM AND CNDT.DEL_FLAG = '0') AS PR_BUYER_CD , HD.SIGN_STATUS , HD.EXEC_TYPE , HD.EXEC_SUBJECT ,(SELECT LISTAGG(VENDOR_CD, ',') WITHIN GROUP(ORDER BY VENDOR_CD) FROM (SELECT DISTINCT VD.VENDOR_CD FROM STOCCNVD VD WHERE VD.GATE_CD = HD.GATE_CD AND VD.BUYER_CD = HD.BUYER_CD AND VD.EXEC_NUM = HD.EXEC_NUM AND VD.DEL_FLAG = '0')) AS VENDOR_CDS ,(SELECT LISTAGG(VENDOR_NM, ',') WITHIN GROUP(ORDER BY VENDOR_NM) FROM (SELECT DISTINCT GL.VENDOR_NM FROM STOCCNVD VD LEFT JOIN STOCVNGL GL ON (VD.GATE_CD = GL.GATE_CD AND VD.VENDOR_CD = GL.VENDOR_CD) WHERE VD.GATE_CD = HD.GATE_CD AND VD.BUYER_CD = HD.BUYER_CD AND VD.EXEC_NUM = HD.EXEC_NUM AND VD.DEL_FLAG = '0' AND GL.DEL_FLAG = '0')) AS VENDOR_NMS , HD.CUR, HD.EXEC_AMT, HD.VAT_TYPE ,(HD.EXEC_DATE, 'YYYYMMDD') AS EXEC_DATE , HD.CTRL_USER_ID ,(CASE WHEN (SELECT COUNT(D.EXEC_SQ) FROM STOCCNDT D WHERE D.GATE_CD = HD.GATE_CD AND D.BUYER_CD = HD.BUYER_CD AND D.EXEC_NUM = HD.EXEC_NUM AND D.TCO_YEAR IS NOT NULL AND D.DEL_FLAG = '0') > 0 THEN 'Y' ELSE 'N' END) AS TCO_FLAG FROM STOCCNHD HD WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{ses.companyCd} AND HD.DEL_FLAG = '0'
AND HD.EXEC_TYPE = #{EXEC_TYPE}
AND HD.SIGN_STATUS = #{SIGN_STATUS}
AND (UPPER(HD.EXEC_NUM) LIKE '%' UPPER(#{EXEC_NUM_SUBJECT}) '%' OR UPPER(REPLACE(HD.EXEC_SUBJECT, ' ', '')) LIKE '%' UPPER(REPLACE(#{EXEC_NUM_SUBJECT}, ' ', '')) '%')
) A WHERE 1 = 1
AND A.EXEC_DATE >= #{EXEC_DATE_FROM} AND A.EXEC_DATE <= #{EXEC_DATE_TO}
AND EXISTS (SELECT 1 FROM STOCCNDT WHERE GATE_CD = A.GATE_CD AND BUYER_CD = A.BUYER_CD AND EXEC_NUM = A.EXEC_NUM AND PR_BUYER_CD LIKE '%'UPPER(#{BUYER_CD})'%' AND DEL_FLAG = '0' )
AND UPPER(getBuyerNames(A.GATE_CD, A.BUYER_CD, 'EX', A.EXEC_NUM, NULL, NULL, #{ses.langCd})) LIKE '%' UPPER(#{BUYER_NM}) '%'
AND UPPER(A.VENDOR_CDS) LIKE '%' UPPER(#{VENDOR_CD}) '%'
AND UPPER(A.VENDOR_NMS) LIKE '%' UPPER(#{VENDOR_NM}) '%'
AND A.CTRL_USER_ID = #{CTRL_USER_ID}
AND UPPER(GETUSERNAME(A.GATE_CD, A.CTRL_USER_ID, #{ses.langCd})) LIKE '%' UPPER(#{CTRL_USER_NM}) '%'
ORDER BY A.EXEC_DATE DESC

SELECT SIGN_STATUS FROM STOCCNHD
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND EXEC_NUM = #{EXEC_NUM}
